[data-slot="scroll-area-scrollbar"] {
  --scrollbar-size: 8px;
}
[data-slot="scroll-area-scrollbar"][data-orientation="vertical"] {
  width: var(--scrollbar-size);
}
[data-slot="scroll-area-scrollbar"][data-orientation="horizontal"] {
  height: var(--scrollbar-size);
}

